{"cmd":"# Let's try booting the ISO directly with expect to interact with the boot prompt
cat > /tmp/boot_alpine.exp << 'EXPECT_EOF'
#!/usr/bin/expect -f
set timeout 30

# Start QEMU in background and capture output
spawn qemu-system-x86_64 \
    -m 1024 \
    -cdrom /app/alpine.iso \
    -hda /tmp/alpine_disk.qcow2 \
    -netdev user,id=net0,hostfwd=tcp::2222-:22 \
    -device virtio-net-pci,netdev=net0 \
    -boot d \
    -nographic

# Wait for boot prompt
expect {
    "boot:" {
        puts "Got boot prompt"
    }
    timeout {
        puts "Timeout waiting for boot prompt"
        exit 1
    }
}

# Type the boot command to start Alpine live
send "setup-alpine\r"
expect {
    "Welcome to Alpine Linux" {
        puts "Setup started"
    }
    "boot:" {
        # Try again
        send "setup-alpine\r"
    }
}

# Let it run for a while
sleep 30

# Check if we have a shell
send "\r"
expect {
    "#" {
        puts "Got root shell!"
    }
    "login:" {
        puts "Got login prompt"
        send "root\r"
        expect "#"
        puts "Got root shell after login"
    }
    timeout {
        puts "Timeout - no shell yet"
    }
}

# Now configure SSH
# Set password for root
send "echo 'root:password123' | chpasswd\r"
expect "#"

# Install and start openssh
send "setup-sshd\r"
expect {
    "#" {
        puts "SSH setup done"
    }
    timeout {
        puts "SSH setup timed out"
    }
}

# Start sshd
send "/etc/init.d/sshd start\r"
expect {
    "#" {
        puts "SSHD started"
    }
    timeout {
        puts "SSHD start timed out"
    }
}

# Keep the session alive
interact
EXPECT_EOF
chmod +x /tmp/boot_alpine.exp
echo "Script created""}

{"cmd":"# Search for ISO9660 CD001 signature
python3 -c "
with open('/app/alpine.iso','rb') as f:
    data = f.read(4096)
    idx = data.find(b'CD001')
    if idx >= 0:
        print(f'Found CD001 at offset {idx} (sector {idx//2048})')
    else:
        # Check common ISO sectors
        for sector in [16, 17, 32, 33]:
            chunk = data[sector*2048:(sector+1)*2048] if (sector+1)*2048 <= len(data) else b''
            idx2 = chunk.find(b'CD001')
            if idx2 >= 0:
                print(f'Found CD001 at sector {sector}, offset {sector*2048+idx2}')
        # Also check first few KB for any CD001
        data2 = f.read(65536)
        idx3 = data2.find(b'CD001')
        if idx3 >= 0:
            print(f'Found CD001 at offset {idx3}')
" 2>&1"}
